import React from "react";

const StatisticsTableProducts = (props) => {
    let arrayEntriesProducts = [];
    let count = 1;

    const getStatisticsOfProduct = () => {
        let mapTemp = new Map();
        props.orders.map(order => {
            order.products.map(product => {
                if (props.categoriesStatus) {
                    if (!mapTemp.has(product.category)) {
                        mapTemp.set(product.category, { count: 1, quantity: product.quantity, unit: product.unit });
                    } else {
                        let property = mapTemp.get(product.category);
                        mapTemp.set(product.category, { count: property.count + 1, quantity: property.quantity + product.quantity, unit: property.unit });
                    }
                }
                else {
                    if (!mapTemp.has(product.name)) {
                        mapTemp.set(product.name, { count: 1, quantity: product.quantity, unit: product.unit });
                    } else {
                        let property = mapTemp.get(product.name);
                        mapTemp.set(product.name, { count: property.count + 1, quantity: property.quantity + product.quantity, unit: property.unit });
                    }
                }
            })
        })
        return mapTemp;
    }
    const maxSalesOfProduct = new Map([...getStatisticsOfProduct().entries()].sort((a, b) => b[1].count - a[1].count));

    for (let entry of maxSalesOfProduct){
        arrayEntriesProducts.push(entry);
    }

    let itemProduct = arrayEntriesProducts.map(entry => {
        return <React.Fragment key={entry[0]}>
            <tr key={entry[0]}>
                <td>{count++}</td>
                    <td>{entry[0]}</td>
                        <td>{entry[1].count}</td>
                            <td>{entry[1].quantity}</td>
                                <td>{entry[1].unit}</td>
            </tr>
        </React.Fragment>
    })

    return <React.Fragment>
        <div>
            <div className="table-product_wrapper">
                <span className="table-product_title">Most popular products:</span>
            </div>

            <table>
                <thead >
                <tr>
                    <th>#</th>
                    <th>Name Product</th>
                    <th>Number of times selected</th>
                    <th>Quantity</th>
                    <th>Unit</th>
                </tr>
                </thead>
                <tbody>
                {itemProduct}
                </tbody>
            </table>
        </div>
    </React.Fragment>
}
export default StatisticsTableProducts;
